  1→import React from 'react';
  2→import type { Decorator } from 'storybook/internal/types';
  3→
  4→const DEVICES = {
  5→  iphone14: { name: 'iPhone 14', width: 390, height: 844 },
  6→  iphone14ProMax: { name: 'iPhone 14 Pro Max', width: 430, height: 932 },
  7→  pixel7: { name: 'Pixel 7', width: 412, height: 915 },
  8→} as const;
  9→
 10→type DeviceKey = keyof typeof DEVICES;
 11→
 12→const DEFAULT_DEVICE: DeviceKey = 'iphone14';
 13→
 14→const PHONE_FRAME_GLOBAL = 'phoneFrame';
 15→
 16→export const PhoneFrameDecorator: Decorator = (Story, context) => {
 17→  const frameEnabled = context.globals[PHONE_FRAME_GLOBAL] !== 'off';
 18→  const deviceKey =
 19→    (context.globals.phoneDevice as DeviceKey) || DEFAULT_DEVICE;
 20→  const device = DEVICES[deviceKey] || DEVICES[DEFAULT_DEVICE];
 21→
 22→  if (!frameEnabled) {
 23→    return <Story />;
 24→  }
 25→
 26→  return (
 27→    <div
 28→      style={{
 29→        display: 'flex',
 30→        justifyContent: 'center',
 31→        alignItems: 'flex-start',
 32→        padding: 24,
 33→        minHeight: '100%',
 34→        backgroundColor: '#f0f0f0',
 35→      }}
 36→    >
 37→      <div
 38→        style={{
 39→          width: device.width,
 40→          height: device.height,
 41→          borderRadius: 44,
 42→          border: '6px solid #1a1a1a',
 43→          backgroundColor: '#ffffff',
 44→          overflow: 'hidden',
 45→          boxShadow:
 46→            '0 20px 60px rgba(0,0,0,0.3), 0 0 0 2px rgba(0,0,0,0.1)',
 47→          position: 'relative',
 48→          display: 'flex',
 49→          flexDirection: 'column',
 50→        }}
 51→      >
 52→        {/* Notch */}
 53→        <div
 54→          style={{
 55→            position: 'absolute',
 56→            top: 0,
 57→            left: '50%',
 58→            transform: 'translateX(-50%)',
 59→            width: 126,
 60→            height: 28,
 61→            backgroundColor: '#1a1a1a',
 62→            borderBottomLeftRadius: 18,
 63→            borderBottomRightRadius: 18,
 64→            zIndex: 10,
 65→          }}
 66→        />
 67→        {/* Status bar area */}
 68→        <div style={{ height: 50, flexShrink: 0 }} />
 69→        {/* Content area */}
 70→        <div
 71→          style={{
 72→            flex: 1,
 73→            overflow: 'auto',
 74→          }}
 75→        >
 76→          <Story />
 77→        </div>
 78→        {/* Home indicator */}
 79→        <div
 80→          style={{
 81→            height: 34,
 82→            flexShrink: 0,
 83→            display: 'flex',
 84→            justifyContent: 'center',
 85→            alignItems: 'center',
 86→          }}
 87→        >
 88→          <div
 89→            style={{
 90→              width: 134,
 91→              height: 5,
 92→              backgroundColor: '#1a1a1a',
 93→              borderRadius: 3,
 94→            }}
 95→          />
 96→        </div>
 97→      </div>
 98→    </div>
 99→  );
100→};
101→
102→export const phoneFrameGlobalTypes = {
103→  [PHONE_FRAME_GLOBAL]: {
104→    name: 'Phone Frame',
105→    description: 'Wrap stories in a phone-shaped frame',
106→    toolbar: {
107→      icon: 'mobile',
108→      title: 'Phone Frame',
109→      items: [
110→        { value: 'on', title: 'Frame On', icon: 'mobile' },
111→        { value: 'off', title: 'Frame Off', icon: 'browser' },
112→      ],
113→      dynamicTitle: true,
114→    },
115→  },
116→  phoneDevice: {
117→    name: 'Device',
118→    description: 'Select phone device size',
119→    toolbar: {
120→      icon: 'grow',
121→      title: 'Device',
122→      items: Object.entries(DEVICES).map(([key, device]) => ({
123→        value: key,
124→        title: `${device.name} (${device.width}×${device.height})`,
125→      })),
126→      dynamicTitle: true,
127→    },
128→  },
129→};
130→
131→export const phoneFrameInitialGlobals = {
132→  [PHONE_FRAME_GLOBAL]: 'on',
133→  phoneDevice: DEFAULT_DEVICE,
134→};
