 6→  phoneFrameGlobalTypes,
 7→  phoneFrameInitialGlobals,
 8→} from './decorators/PhoneFrameDecorator';
 9→
10→const preview: Preview = {
11→  decorators: [
12→    PhoneFrameDecorator,
13→    Story => (
14→      <ThemeProvider>
15→        <Story />
16→      </ThemeProvider>
17→    ),
18→  ],
19→  globalTypes: {
20→    ...phoneFrameGlobalTypes,
21→  },
22→  initialGlobals: {
23→    ...phoneFrameInitialGlobals,
24→  },
25→  parameters: {
26→    controls: {
27→      matchers: {
28→        color: /(background|color)$/i,
29→        date: /Date$/i,
30→      },
31→    },
32→  },
33→};
34→
35→export default preview;
